import {
  isProgramError,
  type Address,
  type SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM,
  type SolanaError,
} from "@solana/kit";
import { PIRATE_ACADEMY_PROGRAM_ADDRESS } from "../programs";

/** BadCrewName: Crew name must be 1–24 ASCII characters */
export const PIRATE_ACADEMY_ERROR__BAD_CREW_NAME = 0x1770; // 6000
/** AlreadyGraduated: This pirate already graduated */
export const PIRATE_ACADEMY_ERROR__ALREADY_GRADUATED = 0x1771; // 6001

export type PirateAcademyError =
  | typeof PIRATE_ACADEMY_ERROR__ALREADY_GRADUATED
  | typeof PIRATE_ACADEMY_ERROR__BAD_CREW_NAME;

let pirateAcademyErrorMessages: Record<PirateAcademyError, string> | undefined;
if (process.env.NODE_ENV !== "production") {
  pirateAcademyErrorMessages = {
    [PIRATE_ACADEMY_ERROR__ALREADY_GRADUATED]: `This pirate already graduated`,
    [PIRATE_ACADEMY_ERROR__BAD_CREW_NAME]: `Crew name must be 1–24 ASCII characters`,
  };
}

export function getPirateAcademyErrorMessage(code: PirateAcademyError): string {
  if (process.env.NODE_ENV !== "production") {
    return (pirateAcademyErrorMessages as Record<PirateAcademyError, string>)[
      code
    ];
  }

  return "Error message not available in production bundles.";
}

export function isPirateAcademyError<
  TProgramErrorCode extends PirateAcademyError,
>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    PIRATE_ACADEMY_PROGRAM_ADDRESS,
    code,
  );
}
